const raw = $input.item.json;
const body = (raw.body && raw.body.puesto) ? raw.body : raw;
const puesto = body.puesto;
const industria = body.industria;
const pais = body.pais || 'Chile';
const empresas = body.empresas_referencia || [];
const seniority = body.seniority || 'Senior';
const cantidad = body.cantidad_candidatos || 50;
const habilidades = body.habilidades || [];
const enviarEmail = body.enviar_cold_email || false;
const plantilla = body.plantilla_email || '';
const etapas = body.etapas_entrevista || [];
const TEST_MODE = true;
const TEST_EMAIL = 'raimundo@umine.com';
if (!puesto || !industria) {
  throw new Error('Faltan campos obligatorios: puesto e industria');
}
const searchId = 'search-' + Date.now().toString(36) + '-' + Math.random().toString(36).substr(2, 5);
const seniorityMap = {'Junior': 'junior', 'Semi-Senior': 'senior', 'Senior': 'senior', 'Lead': 'manager', 'Manager': 'manager', 'Director': 'director', 'VP': 'vp', 'C-Level': 'c_suite'};
const paisMap = {'Chile': 'Chile', 'Argentina': 'Argentina', 'Colombia': 'Colombia', 'Mexico': 'Mexico', 'Peru': 'Peru', 'Brasil': 'Brazil', 'LATAM': 'South America', 'Global': ''};
return {
  json: {
    searchId, puesto, industria,
    pais: paisMap[pais] || pais,
    empresas,
    seniority: seniorityMap[seniority] || 'senior',
    cantidad, habilidades,
    enviarEmail: TEST_MODE ? false : enviarEmail,
    plantilla, etapas,
    testMode: TEST_MODE,
    testEmail: TEST_EMAIL
  }
};

const apolloResponse = $input.item.json;
const searchData = $('✅ Validar y Preparar Datos').item.json;
const people = apolloResponse.people || [];
if (people.length === 0) {
  return [{
    json: {
      id: `cand-${searchData.searchId}-0`,
      searchId: searchData.searchId,
      nombre: 'Sin resultados',
      apellido: '',
      nombreCompleto: 'Sin resultados en Apollo',
      cargo: searchData.puesto,
      empresa: '',
      email: '',
      emailOriginal: '',
      emailScore: 'No disponible',
      linkedinUrl: '',
      ubicacion: '',
      industria: '',
      domain: '',
      apolloId: '',
      estado: 'sin_resultados',
      fechaScraping: new Date().toISOString().split('T')[0],
      testMode: searchData.testMode || false,
      _noResults: true
    }
  }];
}
const candidatos = people.map((person, index) => {
  const org = person.organization || {};
  const firstName = person.first_name || '';
  const lastName = person.last_name || person.last_name_obfuscated || '';
  return {
    id: `cand-${searchData.searchId}-${index + 1}`,
    searchId: searchData.searchId,
    nombre: firstName,
    apellido: lastName,
    nombreCompleto: `${firstName} ${lastName}`.trim() || 'Sin nombre',
    cargo: person.title || '',
    empresa: org.name || '',
    email: '',
    emailOriginal: '',
    emailScore: 'Pendiente',
    linkedinUrl: '',
    ubicacion: '',
    industria: '',
    domain: '',
    apolloId: person.id || '',
    estado: 'encontrado',
    fechaScraping: new Date().toISOString().split('T')[0],
    testMode: searchData.testMode || false
  };
});
return candidatos.map(c => ({ json: c }));

const enrichData = $input.item.json;
const candidato = $('📊 Procesar Candidatos Apollo').item.json;
const searchData = $('✅ Validar y Preparar Datos').item.json;
if (candidato._noResults || !candidato.apolloId) {
  return { json: { ...candidato, perfilEnriquecido: false } };
}
const person = enrichData.person || {};
const org = person.organization || {};
const realLastName = person.last_name || candidato.apellido || '';
const realFirstName = person.first_name || candidato.nombre || '';
const realEmail = person.email || '';
const realLinkedin = person.linkedin_url || '';
const city = person.city || '';
const state = person.state || '';
const country = person.country || '';
const ubicacion = city ? `${city}, ${state || country}`.replace(/, $/, '') : (country || '');
const domain = org.primary_domain || '';
const industry = org.industry || '';
const emailOriginal = realEmail;
let emailParaUsar = realEmail;
let emailScore = 'No disponible';
if (realEmail) {
  emailScore = 'Verificado';
  emailParaUsar = searchData.testMode ? searchData.testEmail : realEmail;
} else if (domain && realFirstName) {
  const first = realFirstName.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const last = realLastName.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  emailParaUsar = searchData.testMode ? searchData.testEmail : `${first}.${last}@${domain}`;
  emailScore = 'Sugerido';
}
const employmentHistory = (person.employment_history || []).map(job => ({titulo: job.title || '', empresa: job.organization_name || '', inicio: job.start_date || '', fin: job.end_date || 'Actual', descripcion: job.description || ''}));
const education = (person.education || []).map(edu => ({institucion: edu.school_name || edu.organization_name || '', titulo: edu.degree || '', campo: edu.field_of_study || '', anio: edu.end_date || ''}));
const skills = person.skills || [];
const seniority = person.seniority || '';
const departments = person.departments || [];
const headline = person.headline || '';
const bio = person.bio || '';
const numEmployees = org.estimated_num_employees || '';
const orgIndustry = org.industry || industry;
const orgDescription = org.short_description || '';
const fullName = `${realFirstName} ${realLastName}`.trim();
const safeName = (fullName && fullName !== 'undefined' && !fullName.includes('undefined')) ? fullName : (candidato.nombreCompleto || 'Sin nombre');
return {
  json: {
    id: candidato.id,
    searchId: candidato.searchId,
    nombre: realFirstName || candidato.nombre || 'Sin nombre',
    apellido: realLastName || candidato.apellido || '',
    nombreCompleto: safeName,
    cargo: person.title || candidato.cargo,
    empresa: org.name || candidato.empresa,
    email: emailParaUsar,
    emailOriginal: emailOriginal,
    emailScore: emailScore,
    linkedinUrl: realLinkedin,
    ubicacion: ubicacion,
    industria: orgIndustry,
    domain: domain,
    apolloId: candidato.apolloId,
    estado: 'encontrado',
    fechaScraping: candidato.fechaScraping,
    testMode: candidato.testMode,
    headline,
    bio,
    seniority,
    departments: departments.join(', '),
    skills: skills.join(', '),
    employmentHistory: JSON.stringify(employmentHistory),
    education: JSON.stringify(education),
    orgIndustry,
    orgDescription,
    orgSize: numEmployees,
    perfilEnriquecido: true
  }
};

const allCandidates = $input.all().map(item => item.json);
const searchData = $('✅ Validar y Preparar Datos').first().json;
if (allCandidates.length <= 20) {
  return allCandidates.map(c => ({ json: { ...c, preScored: false, reason: 'Total≤20' } }));
}
const candidatosResumen = allCandidates.map((c, i) => `
${i + 1}. ${c.nombreCompleto} (${c.apolloId})
   Cargo: ${c.cargo || 'N/A'} @ ${c.empresa || 'N/A'}
   Skills: ${(c.skills || '').substring(0, 80)}
   Seniority: ${c.seniority || 'N/A'}`).join('
');
const preScorePrompt = `Eres un headhunter de élite. Tienes ${allCandidates.length} candidatos para evaluar, pero necesitas filtrar solo los TOP 20 mejores.

PUESTO: ${searchData.puesto}
INDUSTRIA: ${searchData.industria}
SENIORITY: ${searchData.seniority}
HABILIDADES: ${(searchData.habilidades || []).join(', ') || 'No especificadas'}

CANDIDATOS:
${candidatosResumen}

RETORNA SOLO IDs Apollo de TOP 20: ["id1", "id2", ...] SIN EXPLICACIONES NI MARKDOWN.`;
return { json: { preScorePrompt, candidatos: allCandidates, totalCandidatos: allCandidates.length } };

const aiResponse = $input.first().json;
const allCandidates = $('🎯 Pre-Score Prompt').first().json.candidatos;
const responseText = aiResponse.content?.[0]?.text || '[]';
let topApolloIds = [];
try {
  const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').replace(/^[^\[]*/, '').replace(/[^\]]*$/, '').trim();
  topApolloIds = JSON.parse(cleaned);
  if (!Array.isArray(topApolloIds)) { topApolloIds = [topApolloIds]; }
} catch (e) {
  console.warn('Pre-score parse error, using first 20');
  topApolloIds = allCandidates.slice(0, 20).map(c => c.apolloId);
}
const filtered = allCandidates.filter(c => topApolloIds.includes(c.apolloId));
const final = filtered.length >= 20 ? filtered.slice(0, 20) : [...filtered, ...allCandidates.filter(c => !topApolloIds.includes(c.apolloId)).slice(0, 20 - filtered.length)];
return final.map(c => ({ json: { ...c, preScored: true, filterMethod: 'claude-smart' } }));

const aggregated = $input.first().json.data;
const searchData = $('✅ Validar y Preparar Datos').first().json;
const candidatosText = aggregated.map((c, i) => `
--- CANDIDATO ${i + 1} ---
Nombre: ${c.nombreCompleto}
Cargo actual: ${c.cargo}
Empresa: ${c.empresa}
Industria empresa: ${c.orgIndustry || ''}
Ubicación: ${c.ubicacion}
Headline: ${c.headline || ''}
Skills: ${c.skills || ''}
Seniority: ${c.seniority || ''}
Employment History: ${c.employmentHistory || '[]'}
Education: ${c.education || '[]'}
Apollo ID: ${c.apolloId}
`).join('
');
const prompt = `Eres un headhunter de élite de clase mundial, con la experiencia de Spencer Stuart, Heidrick & Struggles y Egon Zehnder.

PUESTO BUSCADO: ${searchData.puesto}
INDUSTRIA: ${searchData.industria}
SENIORITY REQUERIDO: ${searchData.seniority}
HABILIDADES REQUERIDAS: ${JSON.stringify(searchData.habilidades || [])}

CANDIDATOS A EVALUAR (TOP 20 PRE-FILTRADOS):
${candidatosText}

Para CADA candidato, genera análisis. Responde SOLO con JSON (sin markdown):
[{"apolloId": "ID","score_total": 0-100,"experiencia_relevante": 0-100,"habilidades_tecnicas": 0-100,"seniority_fit": 0-100,"industria_fit": 0-100,"liderazgo": 0-100,"cultura_fit": 0-100,"recomendacion": "AVANZAR|REVISAR|RECHAZAR","resumen": "...","fortalezas": [...],"debilidades": [...],"preguntas_entrevista": [...],"apreciacion_recruiter": "..."}]`;
return { json: { prompt, candidatos: aggregated } };

const aiResponse = $input.first().json;
const candidatos = $('Code in JavaScript').first().json.candidatos;
const rawText = aiResponse.content?.[0]?.text || '';
let scores;
try {
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  scores = JSON.parse(cleaned);
  if (!Array.isArray(scores)) scores = [scores];
} catch (e) {
  scores = [];
}
const results = candidatos.map((cand, i) => {
  const score = scores.find(s => s.apolloId === cand.apolloId) || scores[i] || {};
  return {
    ...cand,
    scoreTotal: score.score_total || 0,
    scoreExperiencia: score.experiencia_relevante || 0,
    scoreHabilidades: score.habilidades_tecnicas || 0,
    scoreSeniority: score.seniority_fit || 0,
    scoreIndustria: score.industria_fit || 0,
    scoreLiderazgo: score.liderazgo || 0,
    scoreCultura: score.cultura_fit || 0,
    recomendacion: score.recomendacion || 'REVISAR',
    resumenIA: score.resumen || '',
    fortalezas: JSON.stringify(score.fortalezas || []),
    debilidades: JSON.stringify(score.debilidades || []),
    preguntasEntrevista: JSON.stringify(score.preguntas_entrevista || []),
    apreciacionRecruiter: score.apreciacion_recruiter || '',
    estado: 'evaluado',
    fechaEvaluacion: new Date().toISOString()
  };
});
return results.map(r => ({ json: r }));

const allItems = $input.all();
const searchId = allItems[0].json.searchId || 'search-' + Date.now().toString(36);
return [{ json: { success: true, search_id: searchId, candidatos_encontrados: allItems.length, candidatos: allItems.map(item => item.json), filtro_aplicado: 'smart-apollo-prescore', metodo: 'Búsqueda de 50 → Pre-score Claude → TOP 20 evaluados' } }];
